// Shared types for video processing across Home and Library pages

export interface SubtitleSettings {
  fontSize: number;
  fontFamily: string;
  textColor: string;
  outlineColor: string;
  outlineWidth: number;
  positionY: number;
  position?: "top" | "center" | "bottom";
  marginV?: number;

  // Shadow effects (Phase 11 - SUB-01)
  shadowDepth?: number;        // 0-4, default 0 (disabled)
  shadowColor?: string;         // Hex color, default "#000000"
  borderStyle?: number;         // 1=outline+shadow, 3=box, default 1

  // Glow effects (Phase 11 - SUB-02)
  enableGlow?: boolean;         // Default false
  glowBlur?: number;            // 0-10, default 0 (disabled)

  // Adaptive sizing (Phase 11 - SUB-03)
  adaptiveSizing?: boolean;     // Default false

  // Text opacity (0-100, default 100 = fully opaque)
  opacity?: number;

  // Word-level animated karaoke (Wave 1.3): words highlight in sync with the
  // voice via per-word ASS {\k} timing tags. Pairs with highlightColor.
  karaoke?: boolean;            // Default false
  highlightColor?: string;      // Hex of the "sung"/active word, default "#FFFF00"
}

// User-saved named preset (distinct from hardcoded CAPTION_PRESETS).
// Persisted at profile level via /profiles/{id}/subtitle-presets.
//
// `settings` captures the shared/default style. `settingsA` / `settingsB` are
// optional per-Meta-variant overrides — present only if the user had an
// explicit override for that tab when the preset was saved. Old presets (pre
// multi-variant support) have only `settings` and apply as shared-only.
export interface UserSubtitlePreset {
  id: string;
  name: string;
  created_at: string;
  settings: SubtitleSettings;
  settingsA?: SubtitleSettings;
  settingsB?: SubtitleSettings;
}

export interface SubtitleLine {
  id: number;
  start: string;
  end: string;
  text: string;
}

export interface Variant {
  variant_index: number;
  variant_name: string;
  final_video: string;
  selected: boolean;
  thumbnail?: string;
}

export interface SecondaryVideo {
  file: File | null;
  keywords: string;
}

export interface JobProgress {
  percentage: number;
  current_step: string;
  estimated_remaining: number;
}

export interface Job {
  job_id: string;
  status: "pending" | "processing" | "completed" | "failed";
  progress: string | number;
  error?: string;
  result?: {
    final_video?: string;
    variants?: Variant[];
    processed_videos?: ProcessedVideo[];
  };
}

export interface ProcessedVideo {
  status: string;
  output_path: string;
}

export interface VideoInfo {
  width: number;
  height: number;
  duration: number;
  fps: number;
  aspect_ratio: string;
  is_vertical: boolean;
}

export interface ExportPreset {
  id: string;
  name: string;
  display_name: string;
  width: number;
  height: number;
  fps: number;
  video_bitrate: string;
  audio_bitrate: string;
  crf: number;
  is_default: boolean;
}

export interface Project {
  id: string;
  name: string;
  description?: string;
  status: "draft" | "generating" | "ready_for_triage" | "processing_finals" | "completed" | "failed" | "error";
  target_duration: number;
  context_text?: string;
  created_at: string;
}

export interface Clip {
  id: string;
  project_id: string;
  variant_index: number;
  raw_video_path: string;
  thumbnail_path?: string;
  duration?: number;
  is_selected: boolean;
  final_video_path?: string;
  final_status?: "pending" | "processing" | "completed" | "failed";
  tts_text?: string;
  srt_content?: string;
  subtitle_settings?: SubtitleSettings;
  is_deleted?: boolean;
  variant_name?: string;
  postiz_status?: string;
  postiz_post_id?: string;
  postiz_scheduled_at?: string;
}

export interface ClipContent {
  tts_text: string;
  srt_content: string;
  subtitle_settings: SubtitleSettings;
}

